   1Ôćĺimport { useCallback, useEffect, useMemo, useRef, useState } from "react";
   2Ôćĺimport type {
   3Ôćĺ	ProviderName,
   4Ôćĺ	RemediationPromptsResponse,
   5Ôćĺ	TargetAgent,
   6Ôćĺ} from "../hooks/useEvaluationApi";
   7Ôćĺimport { useEvaluationApi } from "../hooks/useEvaluationApi";
   8Ôćĺimport {
   9Ôćĺ	type ProviderStatus,
  10Ôćĺ	useProviderDetection,
  11Ôćĺ} from "../hooks/useProviderDetection";
  12Ôćĺimport { useSSE } from "../hooks/useSSE";
  13Ôćĺimport type { EvaluationOutput, Issue } from "../types/evaluation";
  14Ôćĺimport {
  15Ôćĺ	getImpactBadgeClass,
  16Ôćĺ	getImpactLabel,
  17Ôćĺ	getIssueSeverity,
  18Ôćĺ	getIssueType,
  19Ôćĺ	getSeverityColor,
  20Ôćĺ	getSeverityLevel,
  21Ôćĺ} from "../types/evaluation";
  22Ôćĺimport type {
  23Ôćĺ	IRemediationProgressState,
  24Ôćĺ	RemediationHistoryItem,
  25Ôćĺ	RemediationResult,
  26Ôćĺ} from "../types/remediation";
  27Ôćĺimport {
  28Ôćĺ	countPackmindArtifacts,
  29Ôćĺ	formatArtifactCount,
  30Ôćĺ} from "../utils/packmind-artifacts";
  31Ôćĺimport { AGENT_GENERATED_FILES, agentLogoMap } from "./AgentLogos";
  32Ôćĺimport { RemediationHistory } from "./RemediationHistory";
  33Ôćĺimport { RemediationProgress } from "./RemediationProgress";
  34Ôćĺimport { CopyButton } from "./shared/CopyButton";
  35Ôćĺimport { Modal } from "./shared/Modal";
  36Ôćĺimport { PackmindLogo } from "./shared/PackmindLogo";
  37Ôćĺimport { PackmindProductTourModal } from "./shared/PackmindProductTourModal";
  38Ôćĺ
  39Ôćĺconst PROVIDER_EXECUTION_INFO: Record<
  40Ôćĺ	ProviderName,
  41Ôćĺ	{ writeCommand: string; securityNote: string }
  42Ôćĺ> = {
  43Ôćĺ	claude: {
  44Ôćĺ		writeCommand:
  45Ôćĺ			"claude -p --output-format json --no-session-persistence --disable-slash-commands --dangerously-skip-permissions",
  46Ôćĺ		securityNote:
  47Ôćĺ			"--dangerously-skip-permissions bypasses all file-write prompts",
  48Ôćĺ	},
  49Ôćĺ	cursor: {
  50Ôćĺ		writeCommand: "agent -p --output-format json --force",
  51Ôćĺ		securityNote: "--force allows writes without confirmation",
  52Ôćĺ	},
  53Ôćĺ	codex: {
  54Ôćĺ		writeCommand:
  55Ôćĺ			"codex exec --json --full-auto --sandbox workspace-write --skip-git-repo-check",
  56Ôćĺ		securityNote:
  57Ôćĺ			"--full-auto autonomous execution, writes restricted to workspace",
  58Ôćĺ	},
  59Ôćĺ	opencode: {
  60Ôćĺ		writeCommand:
  61Ôćĺ			"opencode run --format json --model openai/gpt-5.3-codex --variant medium",
  62Ôćĺ		securityNote: "No sandbox restrictions documented",
  63Ôćĺ	},
  64Ôćĺ	"github-copilot": {
  65Ôćĺ		writeCommand:
  66Ôćĺ			"copilot -p <prompt> -s --no-ask-user --no-custom-instructions --allow-all-tools",
  67Ôćĺ		securityNote: "--allow-all-tools + --no-ask-user = fully autonomous",
  68Ôćĺ	},
  69Ôćĺ	random: {
  70Ôćĺ		writeCommand: "(depends on selected provider)",
  71Ôćĺ		securityNote: "Depends on selected provider",
  72Ôćĺ	},
  73Ôćĺ};
  74Ôćĺ
  75Ôćĺtype Phase = "idle" | "progress";
  76Ôćĺ
  77Ôćĺinterface RemediateTabProps {
  78Ôćĺ	evaluationId: string | null;
  79Ôćĺ	evaluationData: EvaluationOutput | null;
  80Ôćĺ	selectedIssueKeys: Set<string>;
  81Ôćĺ	issueKeyMap: Map<string, Issue>;
  82Ôćĺ	onRemoveIssue: (key: string) => void;
  83Ôćĺ	onClearAll: () => void;
  84Ôćĺ	cloudMode?: boolean;
  85Ôćĺ	repositoryUrl?: string | null;
  86Ôćĺ}
  87Ôćĺ
  88Ôćĺexport function RemediateTab({
  89Ôćĺ	evaluationId,
  90Ôćĺ	evaluationData,
  91Ôćĺ	selectedIssueKeys,
  92Ôćĺ	issueKeyMap,
  93Ôćĺ	onRemoveIssue,
  94Ôćĺ	onClearAll,
  95Ôćĺ	cloudMode = false,
  96Ôćĺ	repositoryUrl,
  97Ôćĺ}: RemediateTabProps) {
  98Ôćĺ	const api = useEvaluationApi();
  99Ôćĺ	const providerDetection = useProviderDetection();
 100Ôćĺ
 101Ôćĺ	const [showTourModal, setShowTourModal] = useState(false);
 102Ôćĺ
 103Ôćĺ	// Phase: idle (config visible) or progress (SSE running)
 104Ôćĺ	const [phase, setPhase] = useState<Phase>("idle");
 105Ôćĺ	const [targetAgent, setTargetAgent] = useState<TargetAgent>("agents-md");
 106Ôćĺ	const [selectedProvider, setSelectedProvider] =
 107Ôćĺ		useState<ProviderName>("claude");
 108Ôćĺ	const [isExecuting, setIsExecuting] = useState(false);
 109Ôćĺ	const [showConfirmModal, setShowConfirmModal] = useState(false);
 110Ôćĺ	const [executeError, setExecuteError] = useState<string | null>(null);
 111Ôćĺ
 112Ôćĺ	// History state
 113Ôćĺ	const [remediations, setRemediations] = useState<RemediationHistoryItem[]>(
 114Ôćĺ		[],
 115Ôćĺ	);
 116Ôćĺ
 117Ôćĺ	// SSE state
 118Ôćĺ	const [sseUrl, setSseUrl] = useState<string | null>(null);
 119Ôćĺ	const [, setActiveRemediationId] = useState<string | null>(null);
 120Ôćĺ	const activeRemediationIdRef = useRef<string | null>(null);
 121Ôćĺ	const [autoExpandRemediationId, setAutoExpandRemediationId] = useState<
 122Ôćĺ		string | null
 123Ôćĺ	>(null);
 124Ôćĺ	const [progressState, setProgressState] = useState<IRemediationProgressState>(
 125Ôćĺ		{
 126Ôćĺ			status: "queued",
 127Ôćĺ			logs: [],
 128Ôćĺ		},
 129Ôćĺ	);
 130Ôćĺ
 131Ôćĺ	// Legacy prompt generation state
 132Ôćĺ	const [isGenerating, setIsGenerating] = useState(false);
 133Ôćĺ	const [generateError, setGenerateError] = useState<string | null>(null);
 134Ôćĺ	const [prompts, setPrompts] = useState<RemediationPromptsResponse | null>(
 135Ôćĺ		null,
 136Ôćĺ	);
 137Ôćĺ
 138Ôćĺ	// Detect providers on mount
 139Ôćĺ	useEffect(() => {
 140Ôćĺ		if (providerDetection.status === "idle") {
 141Ôćĺ			providerDetection.detectProviders();
 142Ôćĺ		}
 143Ôćĺ	}, [providerDetection]);
 144Ôćĺ
 145Ôćĺ	// Load remediation history on mount / evaluationId change
 146Ôćĺ	const refreshHistory = useCallback(async () => {
 147Ôćĺ		if (!evaluationId) return;
 148Ôćĺ		const data = await api.getRemediationsForEvaluation(evaluationId);
 149Ôćĺ		setRemediations(data.remediations);
 150Ôćĺ		return data;
 151Ôćĺ	}, [evaluationId, api]);
 152Ôćĺ
 153Ôćĺ	useEffect(() => {
 154Ôćĺ		if (!evaluationId) return;
 155Ôćĺ
 156Ôćĺ		let cancelled = false;
 157Ôćĺ
 158Ôćĺ		async function loadRemediations() {
 159Ôćĺ			const data = await api.getRemediationsForEvaluation(evaluationId!);
 160Ôćĺ			if (cancelled) return;
 161Ôćĺ
 162Ôćĺ			setRemediations(data.remediations);
 163Ôćĺ
 164Ôćĺ			// If there's an active job, connect SSE
 165Ôćĺ			if (data.activeJob) {
 166Ôćĺ				activeRemediationIdRef.current = data.activeJob.id;
 167Ôćĺ				setActiveRemediationId(data.activeJob.id);
 168Ôćĺ				setSseUrl(
 169Ôćĺ					`${window.location.origin}/api/remediation/${data.activeJob.id}/progress`,
 170Ôćĺ				);
 171Ôćĺ				setProgressState({
 172Ôćĺ					status: data.activeJob.status as "queued" | "running",
 173Ôćĺ					logs: [],
 174Ôćĺ				});
 175Ôćĺ				setPhase("progress");
 176Ôćĺ			}
 177Ôćĺ		}
 178Ôćĺ
 179Ôćĺ		loadRemediations();
 180Ôćĺ
 181Ôćĺ		return () => {
 182Ôćĺ			cancelled = true;
 183Ôćĺ		};
 184Ôćĺ	}, [evaluationId, api]);
 185Ôćĺ
 186Ôćĺ	// Available providers for the selector
 187Ôćĺ	const availableProviders = useMemo(() => {
 188Ôćĺ		const providers: ProviderStatus[] = [];
 189Ôćĺ		for (const p of providerDetection.providers.values()) {
 190Ôćĺ			if (p.available && p.name !== "random") {
 191Ôćĺ				providers.push(p);
 192Ôćĺ			}
 193Ôćĺ		}
 194Ôćĺ		return providers;
 195Ôćĺ	}, [providerDetection.providers]);
 196Ôćĺ
 197Ôćĺ	// Aggregate Packmind artifact totals across all remediations
 198Ôćĺ	const packmindTotals = useMemo(() => {
 199Ôćĺ		let standards = 0;
 200Ôćĺ		let skills = 0;
 201Ôćĺ		for (const r of remediations) {
 202Ôćĺ			const allActions = [
 203Ôćĺ				...(r.summary?.errorFixActions ?? []),
 204Ôćĺ				...(r.summary?.suggestionEnrichActions ?? []),
 205Ôćĺ			];
 206Ôćĺ			const counts = countPackmindArtifacts(allActions);
 207Ôćĺ			standards += counts.standards;
 208Ôćĺ			skills += counts.skills;
 209Ôćĺ		}
 210Ôćĺ		return { standards, skills };
 211Ôćĺ	}, [remediations]);
 212Ôćĺ
 213Ôćĺ	// Resolve selected issue keys to actual issues, split by type
 214Ôćĺ	const { errorEntries, suggestionEntries } = useMemo(() => {
 215Ôćĺ		const errors: { key: string; issue: Issue }[] = [];
 216Ôćĺ		const suggestions: { key: string; issue: Issue }[] = [];
 217Ôćĺ
 218Ôćĺ		for (const key of selectedIssueKeys) {
 219Ôćĺ			const issue = issueKeyMap.get(key);
 220Ôćĺ			if (!issue) continue;
 221Ôćĺ			const type = getIssueType(issue);
 222Ôćĺ			if (type === "error") {
 223Ôćĺ				errors.push({ key, issue });
 224Ôćĺ			} else {
 225Ôćĺ				suggestions.push({ key, issue });
 226Ôćĺ			}
 227Ôćĺ		}
 228Ôćĺ
 229Ôćĺ		errors.sort(
 230Ôćĺ			(a, b) => getIssueSeverity(b.issue) - getIssueSeverity(a.issue),
 231Ôćĺ		);
 232Ôćĺ		const impactOrder: Record<string, number> = {
 233Ôćĺ			High: 0,
 234Ôćĺ			Medium: 1,
 235Ôćĺ			Low: 2,
 236Ôćĺ		};
 237Ôćĺ		suggestions.sort(
 238Ôćĺ			(a, b) =>
 239Ôćĺ				(impactOrder[a.issue.impactLevel ?? "Low"] ?? 2) -
 240Ôćĺ				(impactOrder[b.issue.impactLevel ?? "Low"] ?? 2),
 241Ôćĺ		);
 242Ôćĺ
 243Ôćĺ		return { errorEntries: errors, suggestionEntries: suggestions };
 244Ôćĺ	}, [selectedIssueKeys, issueKeyMap]);
 245Ôćĺ
 246Ôćĺ	const totalSelected = errorEntries.length + suggestionEntries.length;
 247Ôćĺ
 248Ôćĺ	// SSE message handler
 249Ôćĺ	const handleSSEMessage = useCallback(
 250Ôćĺ		// biome-ignore lint/suspicious/noExplicitAny: SSE event data varies by type
 251Ôćĺ		(event: any) => {
 252Ôćĺ			const timestamp = new Date().toISOString();
 253Ôćĺ
 254Ôćĺ			switch (event.type) {
 255Ôćĺ				case "remediation.started":
 256Ôćĺ					setProgressState((prev) => ({
 257Ôćĺ						...prev,
 258Ôćĺ						status: "running",
 259Ôćĺ						logs: [...prev.logs, { timestamp, message: "Remediation started" }],
 260Ôćĺ					}));
 261Ôćĺ					break;
 262Ôćĺ
 263Ôćĺ				case "remediation.progress": {
 264Ôćĺ					const d = event.data ?? {};
 265Ôćĺ					setProgressState((prev) => ({
 266Ôćĺ						...prev,
 267Ôćĺ						...(d.errorCount !== undefined && {
 268Ôćĺ							errorCount: d.errorCount as number,
 269Ôćĺ						}),
 270Ôćĺ						...(d.suggestionCount !== undefined && {
 271Ôćĺ							suggestionCount: d.suggestionCount as number,
 272Ôćĺ						}),
 273Ôćĺ						...(d.totalBatches !== undefined && {
 274Ôćĺ							totalBatches: d.totalBatches as number,
 275Ôćĺ						}),
 276Ôćĺ						...(d.completedBatches !== undefined && {
 277Ôćĺ							completedBatches: d.completedBatches as number,
 278Ôćĺ						}),
 279Ôćĺ						...(d.phase !== undefined && {
 280Ôćĺ							currentPhase: d.phase as "errors" | "suggestions",
 281Ôćĺ						}),
 282Ôćĺ						...(d.runningTotalCostUsd !== undefined && {
 283Ôćĺ							runningTotalCostUsd: d.runningTotalCostUsd as number,
 284Ôćĺ						}),
 285Ôćĺ						...(d.runningTotalDurationMs !== undefined && {
 286Ôćĺ							runningTotalDurationMs: d.runningTotalDurationMs as number,
 287Ôćĺ						}),
 288Ôćĺ						...(d.runningTotalInputTokens !== undefined && {
 289Ôćĺ							runningTotalInputTokens: d.runningTotalInputTokens as number,
 290Ôćĺ						}),
 291Ôćĺ						...(d.runningTotalOutputTokens !== undefined && {
 292Ôćĺ							runningTotalOutputTokens: d.runningTotalOutputTokens as number,
 293Ôćĺ						}),
 294Ôćĺ					}));
 295Ôćĺ					break;
 296Ôćĺ				}
 297Ôćĺ
 298Ôćĺ				case "remediation.step.started": {
 299Ôćĺ					const bi = event.data?.batchInfo as
 300Ôćĺ						| { batchNumber: number; totalBatches: number }
 301Ôćĺ						| undefined;
 302Ôćĺ					const batchLabel = bi
 303Ôćĺ						? ` (batch ${bi.batchNumber}/${bi.totalBatches})`
 304Ôćĺ						: "";
 305Ôćĺ					const issueSummaries = event.data?.issuesSummary as
 306Ôćĺ						| string[]
 307Ôćĺ						| undefined;
 308Ôćĺ					setProgressState((prev) => ({
 309Ôćĺ						...prev,
 310Ôćĺ						currentStep: event.data?.step,
 311Ôćĺ						batchInfo: bi,
 312Ôćĺ						...(issueSummaries && {
 313Ôćĺ							currentBatchIssues: issueSummaries,
 314Ôćĺ						}),
 315Ôćĺ						logs: [
 316Ôćĺ							...prev.logs,
 317Ôćĺ							{
 318Ôćĺ								timestamp,
 319Ôćĺ								message: `Step started: ${event.data?.step}${batchLabel}`,
 320Ôćĺ							},
 321Ôćĺ						],
 322Ôćĺ					}));
 323Ôćĺ					break;
 324Ôćĺ				}
 325Ôćĺ
 326Ôćĺ				case "remediation.step.completed": {
 327Ôćĺ					const bi2 = event.data?.batchInfo as
 328Ôćĺ						| { batchNumber: number; totalBatches: number }
 329Ôćĺ						| undefined;
 330Ôćĺ					const batchLabel2 = bi2
 331Ôćĺ						? ` (batch ${bi2.batchNumber}/${bi2.totalBatches})`
 332Ôćĺ						: "";
 333Ôćĺ					const step = event.data?.step as string | undefined;
 334Ôćĺ					const batchDurationMs = event.data?.batchDurationMs as
 335Ôćĺ						| number
 336Ôćĺ						| undefined;
 337Ôćĺ					const batchCostUsd = event.data?.batchCostUsd as number | undefined;
 338Ôćĺ					const batchInputTokens = event.data?.batchInputTokens as
 339Ôćĺ						| number
 340Ôćĺ						| undefined;
 341Ôćĺ					const batchOutputTokens = event.data?.batchOutputTokens as
 342Ôćĺ						| number
 343Ôćĺ						| undefined;
 344Ôćĺ
 345Ôćĺ					const hasBatchStats =
 346Ôćĺ						batchDurationMs !== undefined && batchCostUsd !== undefined;
 347Ôćĺ					let logMessage = `Step completed: ${step}${batchLabel2}`;
 348Ôćĺ					if (hasBatchStats) {
 349Ôćĺ						const phaseName =
 350Ôćĺ							step === "executing_error_fix"
 351Ôćĺ								? "Error fix"
 352Ôćĺ								: "Suggestion enrich";
 353Ôćĺ						const label = bi2
 354Ôćĺ							? `${phaseName} batch ${bi2.batchNumber}/${bi2.totalBatches}`
 355Ôćĺ							: phaseName;
 356Ôćĺ						logMessage = `${label} completed: ${Math.round(batchDurationMs / 1000)}s, $${batchCostUsd.toFixed(4)}`;
 357Ôćĺ					}
 358Ôćĺ
 359Ôćĺ					setProgressState((prev) => ({
 360Ôćĺ						...prev,
 361Ôćĺ						batchInfo: undefined,
 362Ôćĺ						currentBatchIssues: undefined,
 363Ôćĺ						...(hasBatchStats && {
 364Ôćĺ							lastBatchStats: {
 365Ôćĺ								durationMs: batchDurationMs!,
 366Ôćĺ								costUsd: batchCostUsd!,
 367Ôćĺ								inputTokens: batchInputTokens ?? 0,
 368Ôćĺ								outputTokens: batchOutputTokens ?? 0,
 369Ôćĺ							},
 370Ôćĺ						}),
 371Ôćĺ						logs: [...prev.logs, { timestamp, message: logMessage }],
 372Ôćĺ					}));
 373Ôćĺ					break;
 374Ôćĺ				}
 375Ôćĺ
 376Ôćĺ				case "remediation.completed": {
 377Ôćĺ					setProgressState((prev) => ({
 378Ôćĺ						...prev,
 379Ôćĺ						status: "completed",
 380Ôćĺ						result: event.data?.result as RemediationResult | undefined,
 381Ôćĺ						logs: [
 382Ôćĺ							...prev.logs,
 383Ôćĺ							{ timestamp, message: "Remediation completed" },
 384Ôćĺ						],
 385Ôćĺ					}));
 386Ôćĺ					// Reset to idle, refresh history, clear selection
 387Ôćĺ					// Capture completed remediation ID for auto-expand
 388Ôćĺ					if (activeRemediationIdRef.current) {
 389Ôćĺ						setAutoExpandRemediationId(activeRemediationIdRef.current);
 390Ôćĺ					}
 391Ôćĺ					activeRemediationIdRef.current = null;
 392Ôćĺ					setActiveRemediationId(null);
 393Ôćĺ					setSseUrl(null);
 394Ôćĺ					setPhase("idle");
 395Ôćĺ					onClearAll();
 396Ôćĺ					refreshHistory();
 397Ôćĺ					break;
 398Ôćĺ				}
 399Ôćĺ
 400Ôćĺ				case "remediation.failed":
 401Ôćĺ					setProgressState((prev) => ({
 402Ôćĺ						...prev,
 403Ôćĺ						status: "failed",
 404Ôćĺ						error: event.data?.error,
 405Ôćĺ						logs: [
 406Ôćĺ							...prev.logs,
 407Ôćĺ							{
 408Ôćĺ								timestamp,
 409Ôćĺ								message: `Failed: ${event.data?.error?.message || "Unknown error"}`,
 410Ôćĺ							},
 411Ôćĺ						],
 412Ôćĺ					}));
 413Ôćĺ					setExecuteError(event.data?.error?.message || "Remediation failed");
 414Ôćĺ					setSseUrl(null);
 415Ôćĺ					activeRemediationIdRef.current = null;
 416Ôćĺ					setActiveRemediationId(null);
 417Ôćĺ					setPhase("idle");
 418Ôćĺ					refreshHistory();
 419Ôćĺ					break;
 420Ôćĺ			}
 421Ôćĺ		},
 422Ôćĺ		[onClearAll, refreshHistory],
 423Ôćĺ	);
 424Ôćĺ
 425Ôćĺ	useSSE({
 426Ôćĺ		url: sseUrl,
 427Ôćĺ		onMessage: handleSSEMessage,
 428Ôćĺ	});
 429Ôćĺ
 430Ôćĺ	// Execute remediation
 431Ôćĺ	const handleExecute = useCallback(async () => {
 432Ôćĺ		if (!evaluationId || totalSelected === 0) return;
 433Ôćĺ
 434Ôćĺ		setIsExecuting(true);
 435Ôćĺ		setExecuteError(null);
 436Ôćĺ		setPrompts(null);
 437Ôćĺ
 438Ôćĺ		try {
 439Ôćĺ			const issues = [
 440Ôćĺ				...errorEntries.map((e) => e.issue),
 441Ôćĺ				...suggestionEntries.map((e) => e.issue),
 442Ôćĺ			];
 443Ôćĺ
 444Ôćĺ			const response = await api.executeRemediation(
 445Ôćĺ				evaluationId,
 446Ôćĺ				issues,
 447Ôćĺ				targetAgent,
 448Ôćĺ				selectedProvider,
 449Ôćĺ			);
 450Ôćĺ
 451Ôćĺ			activeRemediationIdRef.current = response.remediationId;
 452Ôćĺ			setActiveRemediationId(response.remediationId);
 453Ôćĺ			setSseUrl(response.sseUrl);
 454Ôćĺ			setProgressState({ status: "queued", logs: [] });
 455Ôćĺ			setPhase("progress");
 456Ôćĺ		} catch (err) {
 457Ôćĺ			const message =
 458Ôćĺ				err instanceof Error ? err.message : "Failed to start remediation";
 459Ôćĺ			setExecuteError(message);
 460Ôćĺ		} finally {
 461Ôćĺ			setIsExecuting(false);
 462Ôćĺ		}
 463Ôćĺ	}, [
 464Ôćĺ		evaluationId,
 465Ôćĺ		totalSelected,
 466Ôćĺ		errorEntries,
 467Ôćĺ		suggestionEntries,
 468Ôćĺ		targetAgent,
 469Ôćĺ		selectedProvider,
 470Ôćĺ		api,
 471Ôćĺ	]);
 472Ôćĺ
 473Ôćĺ	// Generate prompts (legacy copy-paste mode)
 474Ôćĺ	const handleGeneratePrompts = useCallback(async () => {
 475Ôćĺ		if (!evaluationId || totalSelected === 0) return;
 476Ôćĺ
 477Ôćĺ		setIsGenerating(true);
 478Ôćĺ		setGenerateError(null);
 479Ôćĺ
 480Ôćĺ		try {
 481Ôćĺ			const issues = [
 482Ôćĺ				...errorEntries.map((e) => e.issue),
 483Ôćĺ				...suggestionEntries.map((e) => e.issue),
 484Ôćĺ			];
