389Ôćĺinterface UnifiedFileEntry {
390Ôćĺ	key: string;
391Ôćĺ	actions: RemediationAction[];
392Ôćĺ	fileChanges: FileChange[];
393Ôćĺ	totalAdditions: number;
394Ôćĺ	totalDeletions: number;
395Ôćĺ	displayStatus: "added" | "modified" | "deleted" | null;
396Ôćĺ}
397Ôćĺ
398Ôćĺfunction buildUnifiedEntries(result: RemediationResult): {
399Ôćĺ	entries: UnifiedFileEntry[];
400Ôćĺ	skippedActions: RemediationAction[];
401Ôćĺ} {
402Ôćĺ	const allActions = result.summary?.parsed
403Ôćĺ		? [
404Ôćĺ				...result.summary.errorFixActions,
405Ôćĺ				...result.summary.suggestionEnrichActions,
406Ôćĺ			]
407Ôćĺ		: [];
408Ôćĺ
409Ôćĺ	const addressedActions = allActions.filter((a) => a.status !== "skipped");
410Ôćĺ	const skippedActions = allActions.filter((a) => a.status === "skipped");
411Ôćĺ
412Ôćĺ	// Group addressed actions by file key
413Ôćĺ	const groupMap = new Map<string, RemediationAction[]>();
414Ôćĺ	for (const action of addressedActions) {
415Ôćĺ		const key = action.file ?? "General changes";
416Ôćĺ		if (!groupMap.has(key)) groupMap.set(key, []);
417Ôćĺ		groupMap.get(key)?.push(action);
418Ôćĺ	}
419Ôćĺ
420Ôćĺ	// Track which fileChanges have been matched
421Ôćĺ	const matchedFilePaths = new Set<string>();
422Ôćĺ
423Ôćĺ	const entriesFromActions: UnifiedFileEntry[] = [...groupMap.keys()].map(
424Ôćĺ		(key) => {
425Ôćĺ			const filenames = key.split(" + ").map((f) => f.trim());
426Ôćĺ			const matched: FileChange[] = [];
427Ôćĺ			for (const filename of filenames) {
428Ôćĺ				for (const fc of result.fileChanges) {
429Ôćĺ					if (fc.path.endsWith(filename)) {
430Ôćĺ						matched.push(fc);
431Ôćĺ						matchedFilePaths.add(fc.path);
432Ôćĺ					}
433Ôćĺ				}
434Ôćĺ			}
435Ôćĺ			const totalAdditions = matched.reduce((s, fc) => s + fc.additions, 0);
436Ôćĺ			const totalDeletions = matched.reduce((s, fc) => s + fc.deletions, 0);
437Ôćĺ			const displayStatus = computeDisplayStatus(matched);
438Ôćĺ			return {
439Ôćĺ				key,
440Ôćĺ				actions: groupMap.get(key) ?? [],
441Ôćĺ				fileChanges: matched,
442Ôćĺ				totalAdditions,
443Ôćĺ				totalDeletions,
444Ôćĺ				displayStatus,
445Ôćĺ			};
446Ôćĺ		},
447Ôćĺ	);
448Ôćĺ
449Ôćĺ	// Add fileChanges not matched by any action group
450Ôćĺ	const unmatchedEntries: UnifiedFileEntry[] = result.fileChanges
451Ôćĺ		.filter((fc) => !matchedFilePaths.has(fc.path))
452Ôćĺ		.map((fc) => ({
453Ôćĺ			key: fc.path,
454Ôćĺ			actions: [],
455Ôćĺ			fileChanges: [fc],
456Ôćĺ			totalAdditions: fc.additions,
457Ôćĺ			totalDeletions: fc.deletions,
458Ôćĺ			displayStatus: fc.status,
459Ôćĺ		}));
460Ôćĺ
461Ôćĺ	// Sort: "General changes" last, then alphabetical
462Ôćĺ	const allEntries = [...entriesFromActions, ...unmatchedEntries].sort(
463Ôćĺ		(a, b) => {
464Ôćĺ			if (a.key === "General changes") return 1;
465Ôćĺ			if (b.key === "General changes") return -1;
466Ôćĺ			return a.key.localeCompare(b.key);
467Ôćĺ		},
468Ôćĺ	);
469Ôćĺ
470Ôćĺ	return { entries: allEntries, skippedActions };
471Ôćĺ}
472Ôćĺ
473Ôćĺfunction computeDisplayStatus(
474Ôćĺ	fileChanges: FileChange[],
475Ôćĺ): "added" | "modified" | "deleted" | null {
476Ôćĺ	if (fileChanges.length === 0) return null;
477Ôćĺ	// Priority: modified > deleted > added
478Ôćĺ	if (fileChanges.some((fc) => fc.status === "modified")) return "modified";
479Ôćĺ	if (fileChanges.some((fc) => fc.status === "deleted")) return "deleted";
480Ôćĺ	return "added";
481Ôćĺ}
482Ôćĺ
483Ôćĺtype SectionType = "rules" | "skills" | "context" | "other";
484Ôćĺ
485Ôćĺinterface GroupedSection {
486Ôćĺ	type: SectionType;
487Ôćĺ	label: string;
488Ôćĺ	entries: UnifiedFileEntry[];
489Ôćĺ}
