491Ôćĺfunction categorizeEntry(entry: UnifiedFileEntry): SectionType {
492Ôćĺ	// Primary: use outputType from first action
493Ôćĺ	if (entry.actions.length > 0) {
494Ôćĺ		const outputType = entry.actions[0].outputType;
495Ôćĺ		if (outputType === "standard") return "rules";
496Ôćĺ		if (outputType === "skill") return "skills";
497Ôćĺ		if (outputType === "generic") return "context";
498Ôćĺ	}
499Ôćĺ	// Fallback: path-based heuristics for unmatched entries
500Ôćĺ	const key = entry.key.toLowerCase();
501Ôćĺ	if (key.includes("agents.md") || key.includes("claude.md")) return "context";
502Ôćĺ	if (key.includes("/rules/") || key.includes("/standards/")) return "rules";
503Ôćĺ	if (key.includes("/skills/")) return "skills";
504Ôćĺ	return "other";
505Ôćĺ}
506Ôćĺ
507Ôćĺfunction groupEntriesBySections(entries: UnifiedFileEntry[]): GroupedSection[] {
508Ôćĺ	const buckets: Record<SectionType, UnifiedFileEntry[]> = {
509Ôćĺ		rules: [],
510Ôćĺ		skills: [],
511Ôćĺ		context: [],
512Ôćĺ		other: [],
513Ôćĺ	};
514Ôćĺ	for (const entry of entries) {
515Ôćĺ		buckets[categorizeEntry(entry)].push(entry);
516Ôćĺ	}
517Ôćĺ	const sectionDefs: { type: SectionType; label: string }[] = [
518Ôćĺ		{ type: "rules", label: "Rules" },
519Ôćĺ		{ type: "skills", label: "Skills" },
520Ôćĺ		{ type: "context", label: "Context Files" },
521Ôćĺ		{ type: "other", label: "Other" },
522Ôćĺ	];
523Ôćĺ	return sectionDefs
524Ôćĺ		.filter((s) => buckets[s.type].length > 0)
525Ôćĺ		.map((s) => ({ ...s, entries: buckets[s.type] }));
526Ôćĺ}
