154Ôćĺ
155Ôćĺ			// Remap issue locations from CLAUDE.md Ôćĺ AGENTS.md for consolidated pairs
156Ôćĺ			if (colocatedPairs.length > 0) {
157Ôćĺ				const claudeToAgents = new Map(
158Ôćĺ					colocatedPairs.map((p) => [p.claudePath, p.agentsPath]),
159Ôćĺ				);
160Ôćĺ				for (const issue of [...errors, ...suggestions]) {
161Ôćĺ					if (issue.location?.file && claudeToAgents.has(issue.location.file)) {
162Ôćĺ						issue.location.file = claudeToAgents.get(issue.location.file)!;
163Ôćĺ					}
164Ôćĺ				}
165Ôćĺ				// Filter consolidated CLAUDE.md paths from context file list
166Ôćĺ				const claudePaths = new Set(colocatedPairs.map((p) => p.claudePath));
167Ôćĺ				contextFilePaths = contextFilePaths.filter((p) => !claudePaths.has(p));
168Ôćĺ			}
169Ôćĺ
170Ôćĺ			// Step 6: Generate prompts
171Ôćĺ			const input: RemediationInput = {
172Ôćĺ				targetAgent: body.targetAgent,
173Ôćĺ				contextFilePaths,
174Ôćĺ				errors,
175Ôćĺ				suggestions,
176Ôćĺ				technicalInventorySection,
177Ôćĺ				projectSummary,
178Ôćĺ				colocatedPairs: colocatedPairs.length > 0 ? colocatedPairs : undefined,
179Ôćĺ			};
